def _load_likert_test_from_yaml(
    yaml_path: str,
    test_name: str,
    trait_map: Dict[int, str],
    reverse_ids: Iterable[int],
    scale_type: str = "likert_1_5",
) -> PsychometricTest:
    data = _safe_load_yaml(yaml_path)
    if not data:
        raise FileNotFoundError(
            f"Likert test definition YAML '{yaml_path}' is missing or empty."
        )

    if isinstance(data, dict):
        items_src = data.get("items", [])
        instrument_id = str(data.get("id", os.path.basename(yaml_path)))
    else:
        items_src = data
        instrument_id = os.path.basename(yaml_path)

    reverse_ids_set = set(int(r) for r in reverse_ids)
    items: List[PsychometricItem] = []

    for row in items_src:
        if "id" not in row or "text" not in row:
            raise ValueError(
                f"Invalid item in {yaml_path}: each item must have 'id' and 'text'."
            )
        raw_id = row["id"]
        item_id_int = int(raw_id)
        text = str(row["text"])

        trait = trait_map.get(item_id_int)
        if trait is None:
            raise ValueError(
                f"Item id {item_id_int} in {yaml_path} not found in trait map."
            )

        reverse_scored = item_id_int in reverse_ids_set
        items.append(
            PsychometricItem(
                item_id=str(item_id_int),
                text=text,
                trait=trait,
                reverse_scored=reverse_scored,
            )
        )

    return PsychometricTest(
        name=test_name,
        items=items,
        scale_type=scale_type,
        instrument_id=instrument_id,
    )

def _load_crt_test_from_yaml(
    yaml_path: str,
    test_name: str,
    default_trait: str,
    correct_answers: Optional[Dict[str, str]] = None,
) -> PsychometricTest:
    data = _safe_load_yaml(yaml_path)
    if not data:
        raise FileNotFoundError(
            f"CRT test definition YAML '{yaml_path}' is missing or empty."
        )

    if isinstance(data, dict):
        items_src = data.get("items", [])
        instrument_id = str(data.get("id", os.path.basename(yaml_path)))
    else:
        items_src = data
        instrument_id = os.path.basename(yaml_path)

    correct_answers = correct_answers or {}
    items: List[PsychometricItem] = []

    for row in items_src:
        if "id" not in row or "question" not in row:
            raise ValueError(
                f"Invalid CRT item in {yaml_path}: each item must have 'id' and 'question'."
            )
        item_id_str = str(row["id"])
        text = str(row["question"])

        correct = row.get("correct") or row.get("answer") or correct_answers.get(item_id_str)
        # Allow missing correct_answer at load time; downstream scoring can skip until filled
        items.append(
            PsychometricItem(
                item_id=item_id_str,
                text=text,
                trait=default_trait,
                reverse_scored=False,
                correct_answer=str(correct) if correct is not None else None,
            )
        )

    return PsychometricTest(
        name=test_name,
        items=items,
        scale_type="binary",
        instrument_id=instrument_id,
    )

